                    tx <= 1'b1; // Stop Bit
                    if (clk_cnt == BAUD_DIV - 1) begin
                        state   <= IDLE;
                        clk_cnt <= 0;
                        busy    <= 1'b0;
                        done    <= 1'b1;
                    end else begin
                        clk_cnt <= clk_cnt + 1;
                    end
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule
